import re
with open('app/src/pages/SchoolDetailPage.jsx','r',encoding='utf-8') as f:s=f.read()
A={
'PATRISTIC_CIHAI':[("圣事（Sacramentum）","奥古斯丁将圣事定义为'不可见恩典的可见形式'——水洗是可见的，灵魂的洁净是不可见的。德尔图良首次以罗马军队的'誓言'类比洗礼。","奥古斯丁《论洗礼》；德尔图良《论洗礼》"),("自由意志与恩典的辩论","奥古斯丁早年强调自由意志——'意志是灵魂中不受强迫的选择能力'；晚年与伯拉纠论战后强调恩典的绝对优先性——'没有恩典的帮助，意志只能选择恶'。这场辩论预设了此后整个西方神学关于预定论的全部议程。","奥古斯丁《论自由意志》《论恩典与自由意志》"),("修道主义","沙漠教父安东尼的退隐开启了基督教的修道传统。巴西尔以'共修规则'替代独自苦修。奥古斯丁以《规则》为西方修道制度奠定了法律和灵修基础。","阿塔纳修《安东尼传》；巴西尔《隐修规则》"),("殉道（Martyria）","'殉道者的血是教会的种子'——德尔图良。每一次迫害都适得其反地增强了教会。奥古斯丁严格区分：'是死使殉道者尊贵，而非殉道者使死尊贵。'","德尔图良《护教篇》；奥古斯丁《上帝之城》卷一"),("教父的圣经注释","安提阿学派与亚历山大里亚学派的论争贯穿整个教父时代。奥古斯丁在《论基督教教义》中建立了以'爱的双重诫命'为解经终极标准的诠释学。","奥古斯丁《论基督教教义》"),("大公会议","从尼西亚（325）到卡尔西顿（451），主教们聚集以辩论和投票决定正统教义的边界。阿塔纳修以一生的流放和回归亲身见证了会议政治的全部戏剧。","阿塔纳修《论尼西亚公会议的决议》"),("教会的统一与分裂","居普良：'教会之外无拯救'。奥古斯丁在多纳图派论战中区分：教会不是'纯洁者的俱乐部'——它是'麦子和稗子'混合的田地。","居普良《论教会的统一》；奥古斯丁《论洗礼》")],
'SCHOLASTIC_CIHAI':[("天使的形而上学","天使没有身体——他们是纯粹的精神形式。阿奎那：每个天使自身就是一个完整的物种。司各脱：天使的个体化也通过'此性'。","阿奎那《神学大全》第一部第50题"),("神学大全的未完成","阿奎那在1273年弥撒后停止写作——'我所写的一切，与我所见的相比，都像稻草。'","阿奎那传记"),("大学（Universitas）","12-13世纪欧洲最早的大学是从'学者的行会'发展而来的。课程以'七艺'为基础，以神学为顶峰。","哈斯金《大学的兴起》"),("第一因论证","因果链不能无限后退——必须存在一个自身不需要原因的'第一因'——'这就是所有人所说的上帝'。","阿奎那《神学大全》第一部第2题第3条"),("教宗无误论","教宗在特定条件下享有'无误'的特权——'无误'不等于'无罪的'或'全知的'。","阿奎那《神学大全》第二部之二第1题第10条"),("末世论","阿奎那在《神学大全》结尾处理了死亡、审判、天堂、地狱和炼狱——'人最后的目的是在荣福直观中看见上帝的本质'。","阿奎那《神学大全》第三部补编"),("普遍怀疑的方法论","'权威是软弱的——它需要理性来支撑。'阿伯拉尔对隆巴德的批判催生了经院哲学的'辩题'格式。","阿伯拉尔《是与否》前言")],
'RATIONALISM_CIHAI':[("方法论怀疑","笛卡尔将一切可怀疑的东西暂时当作假的——直到找到'我思'这一不可怀疑的第一原理。","笛卡尔《第一哲学沉思集》第一沉思"),("身心统一体","笛卡尔晚年：人不是'心灵住在身体里像舵手在船上'——心灵和身体构成实质统一体。","笛卡尔《灵魂的激情》"),("永恒真理的创造","'2+2=4'不是永恒独立于上帝的——它们是上帝自由意志的创造。","笛卡尔《致梅森的信》"),("泛神论之争","斯宾诺莎'神即自然'引发的两个多世纪的辩论。莱辛承认自己是斯宾诺莎主义者——引发'泛神论之争'（1780年代）。","雅可比《致门德尔松的信》"),("可能世界的逻辑","上帝心智中存在无限多个完整逻辑细节的可能世界。他选择'最简单假设+最丰富现象'的最优组合。","莱布尼茨《神义论》"),("不可分辨者的同一性","'如果两个事物在一切可分辨的属性上都完全一致，那么它们就是同一个事物。'","莱布尼茨《单子论》§9"),("综合先天知识","康德：存在'综合先天知识'——数学（7+5=12）和自然科学基本原理（因果律）。","康德《纯粹理性批判》导论"),("现象与本体的区分","现象可以认识；本体不可以认识但可以被思维。'本体'不是另一个世界——它是这个世界的同一批事物，但我们永远无法以'上帝之眼'看见它们。","康德《纯粹理性批判》"),("理性的兴趣","'我能够知道什么？''我应当做什么？''我可以希望什么？'汇集为：'人是什么？'","康德《纯粹理性批判》先验方法论"),("真理的规则","笛卡尔的认识论准则和著名的'笛卡尔循环'——用清楚明白证明上帝，用上帝保证清楚明白。","笛卡尔《第一哲学沉思集》")],
'EMPIRICISM_CIHAI':[("经验知识的边界","'在开始探索之前，我们有必要考察我们自己的理解力——看看我们的理智适合处理什么对象。'","洛克《人类理智论》导论"),("名义本质与实在本质","科学只能认识名义本质——我们按'感知到的相似性'分类，而非按'实际是什么'分类。","洛克《人类理智论》第三卷第六章"),("知识的三等级","直觉知识最确定；论证知识次之；感觉知识确定性最低，但在实践上足够。","洛克《人类理智论》第四卷第二章"),("第二性质的因果解释","洛克诚实地说：'物质如何能在心灵中产生观念'——我们不知道。","洛克《人类理智论》第二卷第八章"),("实体的一般观念","'我们就像那个印度人——他说世界被一头大象支撑着——但被问到乌龟站在什么上面时，他回答：我不知道。'","洛克《人类理智论》第二卷第23章"),("贝克莱的无神论驳斥","贝克莱的真正目标：物质实体是'无神论和怀疑论'的根基。","贝克莱《人类知识原理》§92-94"),("休谟的两叉戟","把一切既非数学又非经验的断言'扔进火里'——这是经验主义最极端的'意义标准'。","休谟《人类理智研究》第十二章"),("是-应该问题","你不能从纯粹的事实陈述逻辑地推导出价值判断——'休谟的断头台'。","休谟《人性论》第三卷"),("激进经验主义","詹姆斯：'经验本身包含联结关系——正如它包含分离关系一样。'","詹姆斯《激进经验主义文集》"),("苏格兰常识学派的遗产","里德的常识哲学影响了实用主义和日常语言哲学——摩尔举起双手驳斥唯心主义是其精神的回响。","里德；皮尔士；摩尔")],
'ENLIGHTENMENT_CIHAI':[("市民社会","社会秩序不是由立法者设计的——它在无数个体的日常互动中'自发'形成。弗格森《文明社会史论》。","弗格森《文明社会史论》"),("感觉与经验的教育","卢梭《爱弥儿》：12岁前不要教书本知识——让儿童通过直接接触自然学习。","卢梭《爱弥儿》"),("商业社会的德性","商业使风俗温和——不是靠热爱德性而是靠计算利益建立了和平秩序。","孟德斯鸠《论法的精神》；赫希曼"),("历史的哲学","伏尔泰《风俗论》第一次将中国和印度纳入'世界历史'。孔多塞以十阶段划分人类精神的进步。","伏尔泰《风俗论》；孔多塞"),("启蒙与革命","'自由、平等、博爱'——这三个词本身就包含了张力。1793年的恐怖暴露了卢梭'公意'的阴暗面。","托克维尔《旧制度与大革命》"),("东方的镜像","伏尔泰将中国理想化为非基督教文明典范；莱布尼茨痴迷《易经》二进制；孟德斯鸠批判中国专制。","伏尔泰；莱布尼茨；孟德斯鸠"),("宗教的自然史","休谟：宗教起源于对未知原因的恐惧和将自然拟人化的冲动——而非从理性对'第一因'的沉思。","休谟《宗教的自然史》"),("自我招致的不成熟","'如果我有一本书替我理解、一个牧师替我良心——我就不需要自己操心了。'启蒙就是自己承担思考的风险。","康德《什么是启蒙？》"),("理性与信仰的契约","莱辛'三枚戒指'寓言：犹太教、基督教、伊斯兰教——唯一能证明的不是论证，是善行和宽容。","莱辛《智者纳坦》"),("启蒙的辩证法","启蒙理性本身变成了新神话。'工具理性'不仅征服了外部自然，还将人变成可操纵的'物'。","霍克海默与阿多诺《启蒙辩证法》"),("国际法与永久和平","康德：共和制（公民承担战争成本）→自由国家联邦→世界公民法。联合国是部分实现。","康德《永久和平论》")],
'REALISM_CIHAI':[("常识的哲学尊严","外部世界存在——你无法'证明'它（任何论证都预设它），也无法合理'怀疑'它（怀疑行为本身也预设它）。","里德《论人的理智能力》"),("感觉与知觉的区分","笛卡尔的错误：将知觉还原为感觉——导致永远困在心灵内部。","里德《按常识原则探究人类心灵》"),("理论实体的实在性","如果电子不存在，为什么所有独立证据线都汇聚在同一'虚构'上？最好的解释：电子存在。","哈金《表象与干预》"),("自然种类","'水必然是H2O'——这不是约定，而是发现。","克里普克；普特南"),("真理的符合论","'雪是白的'为真，当且仅当雪是白的——这个朴素定义面临三个深刻问题。","亚里士多德；塔斯基"),("形而上学实在论vs内在实在论","'我们无法采用上帝视角——我们永远在某种概念框架内部谈论世界。'","普特南《理性、真理与历史》"),("社会实在","金钱和婚姻是本体论上主观但认识论上客观的——你主观上不承认它是钱，它客观上仍然是钱。","塞尔《社会实在的建构》"),("知觉哲学中的直接实在论","'看见一棵树'是与树的直接知觉接触——不是'接收到感觉材料然后推断树的存在'。","吉布森；麦克道尔"),("科学实在论与悲观归纳","过去的成功理论后来被证明是假的——为什么相信现在的？实在论回应：'结构'是连续的。","劳丹；沃勒尔"),("第二性质的实在性","红色不是'虚构的'——它是视觉系统与光波在真实互动中产生的真实经验。","塞尔《心灵的再发现》"),("第一性质与第二性质的区分史","从伽利略到洛克的经典区分——同时支撑了科学实在论和对实在论的怀疑。","伽利略《试金者》；洛克")],
'IDEALISM_CIHAI':[("统觉的先验统一","'我思必须能够伴随我所有的表象'——否则感官材料就是一堆不归属于任何'我'的碎片。","康德《纯粹理性批判》"),("图式论","因果性的图式是'时间中事件的不可逆先后序列'——这是《纯粹理性批判》最晦涩也最关键的章节。","康德《纯粹理性批判》"),("自律与他律","'自律'——意志为自己立法。'他律'——意志被自身以外的权威支配。自律就是自由。","康德《道德形而上学基础》"),("理性的范导性使用","将理念当作'仿佛'存在的指导原则——而非可以认识的对象——这是理性在自我批判后的合法使用。","康德《纯粹理性批判》"),("苦恼意识","意识渴望与不变的本质合一，但每一努力都以失败告终——因为本质已被投射为'彼岸的上帝'，永远不可企及。","黑格尔《精神现象学》第四章"),("理性的狡计","凯撒跨越卢比孔河是为了自己的野心——但世界精神利用了他的野心来完成更高目的。他很快被刺杀——工具被丢弃。","黑格尔《历史哲学讲演录》"),("家庭-市民社会-国家","家庭=爱的统一。市民社会=自利的交往。国家=两者在更高层面的统一。","黑格尔《法哲学原理》"),("艺术宗教","古希腊雕塑——神以完美人体形式被直观——是艺术作为绝对精神显现的顶峰。艺术的'死亡'是精神上升到更高形式的内在必然性。","黑格尔《美学讲演录》"),("表现主义","情感是'精神在概念之前对自己的前反思性理解'——需要被艺术捕捉，不应被简单'理性化'。","赫尔德；黑格尔；泰勒"),("哲学史即哲学","'最晚的哲学体系是最丰富的'——它把前人的全部真理性内容'扬弃'在自身内部。","黑格尔《哲学史讲演录》导论"),("客观精神","国家是自由在社会制度中的客观实现——不是指任何经验国家，而是国家作为自由的理性概念。","黑格尔《法哲学原理》")],
'LIBERALISM_CIHAI':[("财产权的劳动论证","当一个人将自己的劳动'混合'进自然物，他就将自己的'人格'延伸到那个对象上。限制：不能浪费，为他人留下同样好同样多。","洛克《政府论》下篇"),("政府的目的","政府不是目的——是手段。当政府违背保护权利的目的时，人民有权'诉诸上天'。","洛克《政府论》下篇"),("抵抗权","'征服'不产生合法政府。'篡夺'——未经同意行使权力——是暴政。","洛克《政府论》下篇"),("自由的疆界","密尔不是'绝对自由主义者'——但他坚持限制的举证责任在主张限制的人。","密尔《论自由》"),("宽容的限度","自由主义社会必须宽容不宽容的群体吗？——'宽容的悖论'。","洛克；波普尔"),("宪政主义","不是'让好人统治'——而是'让制度使坏人也无法为害'。分权、司法独立、权利法案。","孟德斯鸠；《联邦党人文集》"),("温和的商业","商业使风俗变得温和——人们关心合同而非征服。自由主义'以利益取代激情'。","孟德斯鸠《论法的精神》"),("民主的两种威胁","多数人的暴政+温和的监护人式专制。","托克维尔《论美国的民主》"),("作为发现的竞争","市场是'发现未知信息的程序'而非'分配已知资源的机制'。","哈耶克"),("作为公平的正义","罗尔斯：正义原则是在'无知之幕'背后会共同选择的原则。差异原则：不平等只有在有利于最不利者时才可接受。","罗尔斯《正义论》"),("自由的两种概念","消极自由——免于干涉；积极自由——自我主宰。积极自由可被扭曲来证成专制。","伯林《两种自由概念》")],
'ROMANTICISM_CIHAI':[("天才（Genius）","天才是'给艺术制定规则的天然秉赋'——不是学习和模仿的结果，而是大自然的馈赠。","康德《判断力批判》"),("崇高","美给人愉悦——崇高给人敬畏，然后转化为更高级的快感。'崇高不在自然中——它在心灵中。'","康德《判断力批判》"),("新神话","启蒙理性'祛魅'了世界。施莱格尔呼唤'新神话'——以现代诗歌和哲学重新为世界注入灵魂。","施莱格尔"),("对中世纪的乡愁","浪漫主义反转启蒙对中世纪的评价：中世纪是信仰和共同体未被商业和理性分裂的时代。","诺瓦利斯《基督教或欧罗巴》"),("爱作为宗教","'爱是灵魂在另一个灵魂中对无限的触摸。'","施莱格尔《卢琴德》"),("诗化哲学","哲学的最高形式不是概念分析而是'诗'——让抽象思想获得艺术品的质感。诺瓦利斯：哲学是'思乡'。","诺瓦利斯；施莱格尔"),("美术与盲目的意志","艺术的极致——音乐——是意志本身的直接肖像。审美经验是对盲目的生存意志的暂时解放。","叔本华《作为意志和表象的世界》"),("夜晚与黑暗的形而上学","诺瓦利斯反转启蒙'光'的隐喻：光让我们看到表面，夜晚让我们触摸深处。","诺瓦利斯《夜的颂歌》"),("蓝色的花","'蓝色花'是渴望本身——它的意义恰恰在于不能被'定义'。","诺瓦利斯"),("浪漫反讽与自我超越","艺术家'飘浮'在自己的作品之上——他的微笑不是嘲讽，是对'任何有限作品都无法满足无限渴望'的觉知。","施莱格尔《雅典娜神殿断片》"),("出神与狂喜","酒神式的狂喜和神秘主义的出神——全身心被卷入更大的宇宙节律中的忘我体验。","荷尔德林；诺瓦利斯；尼采")],
'FEMINISM_CIHAI':[("双重束缚","'不够女人'与'太女人'之间的不可能选择——无论怎么走都是'错'。","弗莱《压迫》"),("家务劳动的政治经济学","家务劳动不算入GDP——但它生产了资本主义最重要的'商品'：劳动力本身。","科斯塔《妇女的力量》"),("身体自主权","'我的身体，我的选择'——身体自主权是女性主义全部具体诉求的共同道德基础。","生殖正义运动"),("强奸文化","'她穿得太少''她喝醉了'——追问受害者做了什么，而非施暴者做了什么。","布朗米勒《违背我们的意愿》"),("女性主义认识论","谁被授权生产知识？谁的知识被认真对待？'将认知者的社会位置纳入反思会产出更强的客观性。'","哈丁；柯林斯"),("性别表演与扮装","操演（performativity）不等于表演（performance）。没有表演者先于操演存在。","巴特勒《性别麻烦》"),("母职的迷思","为什么'不想成为母亲'需要解释，而'想成为母亲'被看作'自然的'？","弗里丹；里奇"),("女性主义四个浪潮","第一波：法律权利。第二波：私人领域权力。第三波：交叉性与酷儿理论。第四波：数字行动主义。","女性主义史学"),("跨国女性主义","'拯救棕色女人脱离棕色男人'——不以西方经验为解放的标准蓝本。","斯皮瓦克；莫汉蒂"),("女性时间","线性时间vs循环时间——'每一次怀孕都重置时间'。","克里斯蒂娃《女性时间》")],
}
for n,e in A.items():
    p=rf'(const {n}\s*=\s*\[.*?)(\n\];)'
    s=re.sub(p,lambda m,ee=e:m.group(1)+',\n    '+',\n    '.join(f'{{word:"{w}",def:"{d}",source:"{src}"}}' for w,d,src in ee)+m.group(2),s,count=1,flags=re.DOTALL)
    print(f'+{len(e)} {n}')
open('app/src/pages/SchoolDetailPage.jsx','w',encoding='utf-8').write(s)
print('Done')
